class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9: Migrate() now manages its own execution strategy and
        // transactions internally. Wrapping it in strategy.Execute() or a
        // manual transaction throws (nested execution strategy / transaction).
        db.Database.Migrate();
    }
}

